using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // Preserve EF Core 8 discriminator property name (default changed to "$type" in EF Core 9).
            // Existing 500K documents and direct SQL queries reference c.Discriminator.
            entity.HasDiscriminator<string>("Discriminator");

            // Preserve EF Core 8 compound id format "Product|123" (EF Core 9 default is just "123").
            // Existing documents use the old format; FindAsync/point-reads would fail without this.
            entity.HasRootDiscriminatorInJsonId(true);
        });

        // HasIndex removed — Cosmos DB provider now throws at startup.
        // Manage indexing via the container's indexing policy (Azure Portal / Bicep / Terraform).
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

